import React, { useState, useMemo } from 'react';
import { ShoppingBag, Search, ChevronRight, LayoutGrid, User, Trash2, Plus, Minus, CreditCard, AlertCircle, ShoppingCart, Settings } from 'lucide-react';
import { Product, CartItem, Order, View } from './types';
import { MOCK_PRODUCTS, formatIDR } from './constants';
import ProductCard from './components/ProductCard';
import AiAssistant from './components/AiAssistant';
import AdminDashboard from './components/AdminDashboard';

const App: React.FC = () => {
  const [view, setView] = useState<View>('home');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('Semua');

  const categories = ['Semua', ...new Set(MOCK_PRODUCTS.map(p => p.category))];

  const filteredProducts = useMemo(() => {
    return MOCK_PRODUCTS.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = selectedCategory === 'Semua' || p.category === selectedCategory;
      return matchesSearch && matchesCategory;
    });
  }, [searchQuery, selectedCategory]);

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const cartTotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const cartCount = cart.reduce((acc, item) => acc + item.quantity, 0);

  const handleCheckout = () => {
    if (cart.length === 0) return;

    const newOrder: Order = {
      id: Math.random().toString(36).substring(7),
      items: [...cart],
      totalAmount: cartTotal,
      date: new Date().toLocaleDateString('id-ID'),
      status: 'Selesai'
    };

    setOrders(prev => [newOrder, ...prev]);
    setCart([]);
    setView('home');
    alert("Pesanan berhasil dibuat! Terima kasih telah berbelanja.");
  };

  if (view === 'admin') {
    return <AdminDashboard orders={orders} onBack={() => setView('home')} />;
  }

  return (
    <div className="min-h-screen flex flex-col">
      {/* Navbar */}
      <nav className="bg-white/80 backdrop-blur-md border-b sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div 
            className="flex items-center gap-2 cursor-pointer" 
            onClick={() => setView('home')}
          >
            <div className="w-10 h-10 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-blue-200">
              <ShoppingBag className="w-6 h-6" />
            </div>
            <span className="text-xl font-black text-gray-900 tracking-tight">TokoKita</span>
          </div>

          <div className="hidden md:flex flex-1 max-w-md mx-8">
            <div className="relative w-full group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 group-focus-within:text-blue-600 transition-colors" />
              <input 
                type="text"
                placeholder="Cari produk impianmu..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full bg-gray-100 border-none rounded-xl py-2 pl-10 pr-4 text-sm focus:ring-2 focus:ring-blue-500 transition-all outline-none"
              />
            </div>
          </div>

          <div className="flex items-center gap-4">
            <button 
              onClick={() => setView('admin')}
              className="p-2 text-gray-500 hover:text-blue-600 transition-colors hidden sm:block"
              title="Admin Dashboard"
            >
              <Settings className="w-5 h-5" />
            </button>
            <button 
              onClick={() => setView('cart')}
              className="relative p-2 text-gray-700 hover:text-blue-600 transition-colors"
            >
              <ShoppingCart className="w-6 h-6" />
              {cartCount > 0 && (
                <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] font-bold w-5 h-5 flex items-center justify-center rounded-full border-2 border-white">
                  {cartCount}
                </span>
              )}
            </button>
            <div className="w-8 h-8 rounded-full bg-gray-200 flex items-center justify-center">
              <User className="w-5 h-5 text-gray-500" />
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl mx-auto px-4 py-8 w-full">
        {view === 'home' && (
          <>
            {/* Hero Section */}
            <div className="relative rounded-3xl overflow-hidden bg-blue-600 p-8 md:p-16 mb-12 text-white shadow-2xl shadow-blue-200">
              <div className="max-w-xl relative z-10">
                <h1 className="text-4xl md:text-5xl font-black mb-6 leading-tight">
                  Belanja Pintar, Hidup Lebih Mudah.
                </h1>
                <p className="text-blue-100 text-lg mb-8 leading-relaxed">
                  Dapatkan penawaran terbaik untuk produk elektronik dan lifestyle terkini. Didukung oleh asisten AI untuk membantu Anda.
                </p>
                <div className="flex gap-4">
                  <button className="bg-white text-blue-600 px-6 py-3 rounded-xl font-bold hover:bg-blue-50 transition-colors flex items-center gap-2">
                    Mulai Belanja <ChevronRight className="w-5 h-5" />
