                </div>
              </div>
              <div className="absolute top-0 right-0 w-1/3 h-full hidden lg:block opacity-20">
                <LayoutGrid className="w-full h-full p-12" />
              </div>
            </div>

            {/* Categories */}
            <div className="flex flex-wrap gap-2 mb-8 items-center">
              <span className="text-sm font-bold text-gray-500 uppercase tracking-wider mr-2">Kategori:</span>
              {categories.map(cat => (
                <button
                  key={cat}
                  onClick={() => setSelectedCategory(cat)}
                  className={`px-4 py-2 rounded-xl text-sm font-semibold transition-all ${
                    selectedCategory === cat 
                      ? 'bg-blue-600 text-white shadow-lg shadow-blue-100' 
                      : 'bg-white text-gray-600 hover:bg-gray-100'
                  }`}
                >
                  {cat}
                </button>
              ))}
            </div>

            {/* Product Grid */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
              {filteredProducts.map(product => (
                <ProductCard 
                  key={product.id} 
                  product={product} 
                  onAddToCart={addToCart} 
                />
              ))}
            </div>

            {filteredProducts.length === 0 && (
              <div className="text-center py-20">
                <AlertCircle className="w-16 h-16 text-gray-300 mx-auto mb-4" />
                <h3 className="text-xl font-bold text-gray-900 mb-2">Produk Tidak Ditemukan</h3>
                <p className="text-gray-500">Coba kata kunci atau kategori lain.</p>
              </div>
            )}
          </>
        )}

        {view === 'cart' && (
          <div className="max-w-4xl mx-auto">
            <h2 className="text-3xl font-black mb-8">Keranjang Belanja</h2>
            {cart.length === 0 ? (
              <div className="bg-white rounded-3xl p-12 text-center border-2 border-dashed border-gray-200">
                <ShoppingCart className="w-20 h-20 text-gray-200 mx-auto mb-6" />
                <h3 className="text-xl font-bold mb-2">Keranjangmu masih kosong</h3>
