                  </div>
                  <button 
                    onClick={handleCheckout}
                    className="w-full bg-blue-600 text-white py-4 rounded-xl font-bold flex items-center justify-center gap-2 hover:bg-blue-700 shadow-xl shadow-blue-100 transition-all"
                  >
                    <CreditCard className="w-5 h-5" />
                    Bayar Sekarang
                  </button>
                </div>
              </div>
            )}
          </div>
        )}
      </main>

      {/* AI Assistant Floating Button & Component */}
      <AiAssistant />

      {/* Footer */}
      <footer className="bg-white border-t py-12">
        <div className="max-w-7xl mx-auto px-4">
          <div className="grid grid-cols-1 md:grid-cols-4 gap-12 mb-12">
            <div className="col-span-1 md:col-span-2">
              <div className="flex items-center gap-2 mb-6">
                <div className="w-8 h-8 bg-blue-600 rounded-xl flex items-center justify-center text-white">
                  <ShoppingBag className="w-5 h-5" />
                </div>
                <span className="text-xl font-black text-gray-900">TokoKita</span>
              </div>
              <p className="text-gray-500 max-w-sm mb-6 leading-relaxed">
                TokoKita adalah platform belanja modern yang mengedepankan kemudahan dan kenyamanan pelanggan dengan bantuan teknologi AI terkini.
              </p>
            </div>
            <div>
              <h4 className="font-bold mb-6 text-gray-900 uppercase tracking-widest text-xs">Belanja</h4>
              <ul className="space-y-4 text-gray-500 text-sm">
