import React, { useState, useMemo } from 'react';
import { ShoppingBag, Search, ChevronRight, LayoutGrid, User, Trash2, Plus, Minus, CreditCard, AlertCircle, ShoppingCart, Settings, LogOut } from 'lucide-react';
import { Product, CartItem, Order, View, AuthState, UserRole } from './types';
import { MOCK_PRODUCTS, formatIDR } from './constants';
import ProductCard from './components/ProductCard';
import AiAssistant from './components/AiAssistant';
import AdminDashboard from './components/AdminDashboard';
import Login from './components/Login';

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({
    isLoggedIn: false,
    role: null,
    username: null
  });
  const [view, setView] = useState<View>('home');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('Semua');

  const categories = ['Semua', ...new Set(MOCK_PRODUCTS.map(p => p.category))];

  const filteredProducts = useMemo(() => {
    return MOCK_PRODUCTS.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = selectedCategory === 'Semua' || p.category === selectedCategory;
      return matchesSearch && matchesCategory;
    });
  }, [searchQuery, selectedCategory]);

  const handleLogin = (role: UserRole, username: string) => {
    setAuth({
      isLoggedIn: true,
      role,
      username
    });
    // If admin logs in, show them the dashboard immediately? 
    // Or let them choose. Let's stay on home but allow dashboard access.
  };

  const handleLogout = () => {
    setAuth({
      isLoggedIn: false,
      role: null,
      username: null
    });
    setView('home');
    setCart([]);
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const cartTotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const cartCount = cart.reduce((acc, item) => acc + item.quantity, 0);

  const handleCheckout = () => {
    if (cart.length === 0) return;

    const newOrder: Order = {
      id: Math.random().toString(36).substring(7),
      items: [...cart],
      totalAmount: cartTotal,
      date: new Date().toLocaleDateString('id-ID'),
      status: 'Selesai'
    };

    setOrders(prev => [newOrder, ...prev]);
    setCart([]);
    setView('home');
    alert("Pesanan berhasil dibuat! Terima kasih telah berbelanja.");
  };

  // If not logged in, show Login screen
  if (!auth.isLoggedIn) {
    return <Login onLogin={handleLogin} />;
  }

  // Admin view restricted
  if (view === 'admin' && auth.role === 'admin') {
    return <AdminDashboard orders={orders} onBack={() => setView('home')} />;
  } else if (view === 'admin' && auth.role !== 'admin') {
    setView('home'); // Redirect if somehow accessed
  }

  return (
    <div className="min-h-screen flex flex-col">
      {/* Navbar */}
      <nav className="bg-white/80 backdrop-blur-md border-b sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div 
            className="flex items-center gap-2 cursor-pointer" 
            onClick={() => setView('home')}
          >
            <div className="w-10 h-10 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-blue-200">
              <ShoppingBag className="w-6 h-6" />
            </div>
            <span className="text-xl font-black text-gray-900 tracking-tight">TokoKita</span>
          </div>

          <div className="hidden md:flex flex-1 max-w-md mx-8">
            <div className="relative w-full group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 group-focus-within:text-blue-600 transition-colors" />
              <input 
                type="text"
                placeholder="Cari produk impianmu..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full bg-gray-100 border-none rounded-xl py-2 pl-10 pr-4 text-sm focus:ring-2 focus:ring-blue-500 transition-all outline-none"
              />
            </div>
          </div>

          <div className="flex items-center gap-2 sm:gap-4">
            {auth.role === 'admin' && (
              <button 
                onClick={() => setView('admin')}
                className={`p-2 transition-colors flex items-center gap-1 ${view === 'admin' ? 'text-blue-600' : 'text-gray-500 hover:text-blue-600'}`}
                title="Admin Dashboard"
              >
                <Settings className="w-5 h-5" />
                <span className="hidden lg:inline text-sm font-bold">Dashboard</span>
              </button>
            )}

            <button 
              onClick={() => setView('cart')}
              className={`relative p-2 transition-colors ${view === 'cart' ? 'text-blue-600' : 'text-gray-700 hover:text-blue-600'}`}
            >
              <ShoppingCart className="w-6 h-6" />
              {cartCount > 0 && (
                <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] font-bold w-5 h-5 flex items-center justify-center rounded-full border-2 border-white">
                  {cartCount}
                </span>
              )}
            </button>

            <div className="h-8 w-px bg-gray-200 hidden sm:block" />

            <div className="flex items-center gap-3">
              <div className="text-right hidden sm:block">
                <p className="text-xs font-bold text-gray-900">{auth.username}</p>
                <p className="text-[10px] text-gray-500 uppercase tracking-tighter">{auth.role}</p>
              </div>
              <button 
                onClick={handleLogout}
                className="p-2 text-gray-400 hover:text-red-500 transition-colors"
                title="Keluar"
              >
                <LogOut className="w-5 h-5" />
              </button>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl mx-auto px-4 py-8 w-full">
        {view === 'home' && (
          <>
            {/* Hero Section */}
            <div className="relative rounded-3xl overflow-hidden bg-blue-600 p-8 md:p-16 mb-12 text-white shadow-2xl shadow-blue-200">
              <div className="max-w-xl relative z-10">
                <h1 className="text-4xl md:text-5xl font-black mb-6 leading-tight">
                  Halo, {auth.username}!<br/>
                  Belanja Pintar Sekarang.
                </h1>
                <p className="text-blue-100 text-lg mb-8 leading-relaxed">
                  Dapatkan penawaran terbaik untuk produk elektronik dan lifestyle terkini. Didukung oleh asisten AI untuk membantu Anda.
                </p>
                <div className="flex gap-4">
                  <button className="bg-white text-blue-600 px-6 py-3 rounded-xl font-bold hover:bg-blue-50 transition-colors flex items-center gap-2">
                    Mulai Belanja <ChevronRight className="w-5 h-5" />
                  </button>
                </div>
              </div>
              <div className="absolute top-0 right-0 w-1/3 h-full hidden lg:block opacity-20">
                <LayoutGrid className="w-full h-full p-12" />
              </div>
            </div>

            {/* Categories */}
            <div className="flex flex-wrap gap-2 mb-8 items-center">
              <span className="text-sm font-bold text-gray-500 uppercase tracking-wider mr-2">Kategori:</span>
              {categories.map(cat => (
                <button
                  key={cat}
                  onClick={() => setSelectedCategory(cat)}
                  className={`px-4 py-2 rounded-xl text-sm font-semibold transition-all ${
                    selectedCategory === cat 
                      ? 'bg-blue-600 text-white shadow-lg shadow-blue-100' 
                      : 'bg-white text-gray-600 hover:bg-gray-100'
                  }`}
                >
                  {cat}
                </button>
              ))}
            </div>

            {/* Product Grid */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
              {filteredProducts.map(product => (
                <ProductCard 
                  key={product.id} 
                  product={product} 
                  onAddToCart={addToCart} 
                />
              ))}
            </div>

            {filteredProducts.length === 0 && (
              <div className="text-center py-20">
                <AlertCircle className="w-16 h-16 text-gray-300 mx-auto mb-4" />
                <h3 className="text-xl font-bold text-gray-900 mb-2">Produk Tidak Ditemukan</h3>
                <p className="text-gray-500">Coba kata kunci atau kategori lain.</p>
              </div>
            )}
          </>
        )}

        {view === 'cart' && (
          <div className="max-w-4xl mx-auto">
            <h2 className="text-3xl font-black mb-8">Keranjang Belanja</h2>
            {cart.length === 0 ? (
              <div className="bg-white rounded-3xl p-12 text-center border-2 border-dashed border-gray-200">
                <ShoppingCart className="w-20 h-20 text-gray-200 mx-auto mb-6" />
                <h3 className="text-xl font-bold mb-2">Keranjangmu masih kosong</h3>
                <p className="text-gray-500 mb-8">Ayo cari produk menarik untuk mengisi keranjangmu!</p>
                <button 
                  onClick={() => setView('home')}
                  className="bg-blue-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-blue-700 transition-all"
                >
                  Lihat Produk
                </button>
              </div>
            ) : (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 space-y-4">
                  {cart.map(item => (
                    <div key={item.id} className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 flex gap-4">
                      <div className="w-24 h-24 rounded-xl overflow-hidden shrink-0">
                        <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
                      </div>
                      <div className="flex-1 flex flex-col justify-between">
                        <div>
                          <h3 className="font-bold text-gray-900">{item.name}</h3>
                          <p className="text-sm text-gray-500">{formatIDR(item.price)}</p>
                        </div>
                        <div className="flex items-center justify-between mt-2">
                          <div className="flex items-center gap-3 bg-gray-50 rounded-lg px-2 py-1">
                            <button onClick={() => updateQuantity(item.id, -1)} className="p-1 hover:text-blue-600">
                              <Minus className="w-4 h-4" />
                            </button>
                            <span className="font-bold text-sm min-w-[20px] text-center">{item.quantity}</span>
                            <button onClick={() => updateQuantity(item.id, 1)} className="p-1 hover:text-blue-600">
                              <Plus className="w-4 h-4" />
                            </button>
                          </div>
                          <button onClick={() => removeFromCart(item.id)} className="text-red-500 hover:text-red-700 p-2">
                            <Trash2 className="w-5 h-5" />
                          </button>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>

                <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 h-fit sticky top-24">
                  <h3 className="text-lg font-bold mb-6">Ringkasan Pesanan</h3>
                  <div className="space-y-4 mb-8 text-sm">
                    <div className="flex justify-between text-gray-500">
                      <span>Subtotal</span>
                      <span>{formatIDR(cartTotal)}</span>
                    </div>
                    <div className="flex justify-between text-gray-500">
                      <span>Biaya Pengiriman</span>
                      <span className="text-green-600 font-bold">Gratis</span>
                    </div>
                    <div className="h-px bg-gray-100 my-4" />
                    <div className="flex justify-between text-lg font-bold text-gray-900">
                      <span>Total</span>
                      <span>{formatIDR(cartTotal)}</span>
                    </div>
                  </div>
                  <button 
                    onClick={handleCheckout}
                    className="w-full bg-blue-600 text-white py-4 rounded-xl font-bold flex items-center justify-center gap-2 hover:bg-blue-700 shadow-xl shadow-blue-100 transition-all"
                  >
                    <CreditCard className="w-5 h-5" />
                    Bayar Sekarang
                  </button>
                </div>
              </div>
            )}
          </div>
        )}
      </main>

      {/* AI Assistant Floating Button & Component */}
      <AiAssistant />

      {/* Footer */}
      <footer className="bg-white border-t py-12">
