interface LoginProps {
  onLogin: (role: UserRole, username: string) => void;
  onRegister: (account: UserAccount) => boolean;
  registeredUsers: UserAccount[];
}

const Login: React.FC<LoginProps> = ({ onLogin, onRegister, registeredUsers }) => {
  const [mode, setMode] = useState<'login' | 'register'>('login');
  const [role, setRole] = useState<UserRole>('user');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    setTimeout(() => {
      if (mode === 'login') {
        if (role === 'admin') {
          if (username === '2284400' && password === 'EL1W8') {
            onLogin('admin', username);
          } else {
            setError('Kredensial Admin Salah!');
          }
        } else {
          // Check registered users
          const user = registeredUsers.find(u => u.username === username && u.password === password);
          if (user) {
            onLogin('user', username);
          } else {
            setError('Username atau Password salah!');
          }
        }
      } else {
        // Register mode
        const success = onRegister({ username, password, role: 'user' });
        if (success) {
          setMode('login');
          setRole('user');
          alert('Pendaftaran Berhasil! Silakan Login.');
        } else {
          setError('Username sudah terdaftar!');
        }
      }
      setIsLoading(false);
    }, 800);
  };

  return (
    <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
      <div className="w-full max-w-md">
