            <ShoppingBag className="w-10 h-10" />
          </div>
          <h1 className="text-3xl font-black text-gray-900 tracking-tight">MWSTORE</h1>
          <p className="text-gray-500 mt-2">{mode === 'login' ? 'Masuk untuk belanja' : 'Buat akun baru'}</p>
        </div>

        <div className="bg-white rounded-3xl shadow-xl border border-gray-100 overflow-hidden">
          {mode === 'login' && (
            <div className="flex p-1 bg-gray-100 m-6 rounded-xl">
              <button
                onClick={() => setRole('user')}
                className={`flex-1 py-2 text-sm font-bold rounded-lg transition-all flex items-center justify-center gap-2 ${
                  role === 'user' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'
                }`}
              >
                <User className="w-4 h-4" />
                Pelanggan
              </button>
              <button
                onClick={() => setRole('admin')}
                className={`flex-1 py-2 text-sm font-bold rounded-lg transition-all flex items-center justify-center gap-2 ${
                  role === 'admin' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'
                }`}
              >
                <ShieldCheck className="w-4 h-4" />
                Admin
              </button>
            </div>
          )}

          <form onSubmit={handleSubmit} className={`p-6 ${mode === 'register' ? 'pt-6' : 'pt-0'} space-y-4`}>
            {error && <div className="p-3 bg-red-50 text-red-600 text-sm rounded-xl font-medium border border-red-100 text-center">{error}</div>}

            <div className="space-y-2">
              <label className="text-sm font-bold text-gray-700 ml-1">Username</label>
              <div className="relative">
                <User className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                <input
                  type="text"
