                <button className="bg-white text-blue-600 px-6 py-3 rounded-xl font-bold hover:bg-blue-50 transition-colors flex items-center gap-2 shadow-xl shadow-blue-900/20">
                  Mulai Jelajah <ChevronRight className="w-5 h-5" />
                </button>
              </div>
              <div className="absolute top-0 right-0 w-1/3 h-full hidden lg:block opacity-10">
                <LayoutGrid className="w-full h-full p-12" />
              </div>
            </div>

            <div className="flex flex-wrap gap-2 mb-8 items-center overflow-x-auto pb-2 scrollbar-hide">
              <span className="text-xs font-black text-gray-400 uppercase tracking-widest mr-2 shrink-0">Filter:</span>
              {categories.map(cat => (
                <button
                  key={cat}
                  onClick={() => setSelectedCategory(cat)}
                  className={`px-5 py-2.5 rounded-xl text-sm font-bold transition-all shrink-0 ${
                    selectedCategory === cat 
