        )}

        {view === 'checkout' && (
          <div className="max-w-4xl mx-auto">
            <button onClick={() => setView('cart')} className="flex items-center gap-2 text-gray-500 hover:text-blue-600 mb-6 font-bold">
              <ChevronRight className="w-5 h-5 rotate-180" />
              Kembali ke Keranjang
            </button>
            <h2 className="text-3xl font-black mb-8">Konfirmasi Pembayaran</h2>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="space-y-6">
                <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
                  <h3 className="font-bold text-lg mb-6 flex items-center gap-2">
                    <Wallet className="w-5 h-5 text-blue-600" />
                    Pilih Metode Pembayaran
                  </h3>
                  <div className="space-y-3">
                    {[
                      { id: 'Transfer Bank', icon: Building2, desc: 'BCA, Mandiri, BNI' },
                      { id: 'E-Wallet', icon: Wallet, desc: 'Dana, OVO, GoPay' },
                      { id: 'QRIS', icon: QrCode, desc: 'Scan Semua Pembayaran' },
                    ].map(method => (
                      <button
                        key={method.id}
                        onClick={() => setPaymentMethod(method.id)}
                        className={`w-full flex items-center gap-4 p-4 rounded-2xl border-2 transition-all text-left ${
                          paymentMethod === method.id 
                            ? 'border-blue-600 bg-blue-50' 
                            : 'border-gray-50 hover:border-gray-200'
                        }`}
                      >
                        <div className={`p-3 rounded-xl ${paymentMethod === method.id ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-500'}`}>
                          <method.icon className="w-5 h-5" />
                        </div>
                        <div className="flex-1">
                          <p className="font-bold text-gray-900">{method.id}</p>
                          <p className="text-xs text-gray-400">{method.desc}</p>
                        </div>
                        {paymentMethod === method.id && <CheckCircle2 className="w-5 h-5 text-blue-600" />}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100 h-fit">
                <h3 className="font-bold text-lg mb-6">Detail Tagihan</h3>
                <div className="space-y-4 mb-8">
                  <div className="max-h-40 overflow-y-auto space-y-2 mb-4">
                    {cart.map(item => (
                      <div key={item.id} className="flex justify-between text-sm">
                        <span className="text-gray-500">{item.name} x{item.quantity}</span>
                        <span className="font-bold text-gray-900">{formatIDR(item.price * item.quantity)}</span>
                      </div>
                    ))}
                  </div>
                  <div className="h-px bg-gray-100" />
                  <div className="flex justify-between items-center py-2">
                    <span className="text-gray-500 text-sm">Metode</span>
                    <span className="text-blue-600 font-bold text-sm">{paymentMethod}</span>
                  </div>
                  <div className="flex justify-between items-center text-xl font-black pt-2">
                    <span>Total Bayar</span>
                    <span className="text-blue-600">{formatIDR(cartTotal)}</span>
                  </div>
                </div>
                <button 
                  onClick={confirmPayment}
                  className="w-full bg-blue-600 text-white py-4 rounded-xl font-bold flex items-center justify-center gap-2 hover:bg-blue-700 shadow-xl shadow-blue-50 transition-all"
                >
                  <CreditCard className="w-5 h-5" />
                  Bayar Sekarang
                </button>
                <p className="text-[10px] text-gray-400 text-center mt-4">
                  Dengan mengklik tombol di atas, Anda menyetujui Ketentuan Layanan MWSTORE.
                </p>
              </div>
            </div>
          </div>
        )}
      </main>

      <AiAssistant />

      <footer className="bg-white border-t py-12">
        <div className="max-w-7xl mx-auto px-4">
          <div className="grid grid-cols-1 md:grid-cols-4 gap-12 mb-12">
            <div className="col-span-1 md:col-span-2">
              <div className="flex items-center gap-2 mb-6">
                <div className="w-8 h-8 bg-blue-600 rounded-xl flex items-center justify-center text-white font-bold">MW</div>
                <span className="text-xl font-black text-gray-900 tracking-tight">MWSTORE</span>
              </div>
              <p className="text-gray-500 max-w-sm mb-6 leading-relaxed">
                MWSTORE adalah destinasi belanja digital terpercaya. Kami menghadirkan inovasi AI untuk meningkatkan pengalaman belanja Anda setiap hari.
              </p>
            </div>
            <div>
              <h4 className="font-bold mb-6 text-gray-900 uppercase tracking-widest text-xs">Belanja</h4>
              <ul className="space-y-4 text-gray-500 text-sm">
