                <li><a href="#" className="hover:text-blue-600 transition-colors">Kategori Populer</a></li>
              </ul>
            </div>
            <div>
              <h4 className="font-bold mb-6 text-gray-900 uppercase tracking-widest text-xs">Dukungan</h4>
              <ul className="space-y-4 text-gray-500 text-sm">
                <li><a href="#" className="hover:text-blue-600 transition-colors">Hubungi Kami</a></li>
                <li><a href="#" className="hover:text-blue-600 transition-colors">FAQ</a></li>
              </ul>
