};

export default App;

import React, { useState, useMemo } from 'react';
import { ShoppingBag, Search, ChevronRight, LayoutGrid, Trash2, Plus, Minus, CreditCard, AlertCircle, ShoppingCart, Settings, LogOut, Wallet, QrCode, Building2, CheckCircle2 } from 'lucide-react';
import { Product, CartItem, Order, View, AuthState, UserRole, UserAccount } from './types';
import { MOCK_PRODUCTS, formatIDR } from './constants';
import ProductCard from './components/ProductCard';
import AiAssistant from './components/AiAssistant';
import AdminDashboard from './components/AdminDashboard';
import Login from './components/Login';

const App: React.FC = () => {
  const [products, setProducts] = useState<Product[]>(MOCK_PRODUCTS);
  const [users, setUsers] = useState<UserAccount[]>([]);
  const [auth, setAuth] = useState<AuthState>({
    isLoggedIn: false,
    role: null,
    username: null
  });
  const [view, setView] = useState<View>('home');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('Semua');
  const [paymentMethod, setPaymentMethod] = useState('Transfer Bank');

  const categories = ['Semua', ...new Set(products.map(p => p.category))];

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = selectedCategory === 'Semua' || p.category === selectedCategory;
      return matchesSearch && matchesCategory;
    });
  }, [searchQuery, selectedCategory, products]);

  const handleLogin = (role: UserRole, username: string) => {
    setAuth({ isLoggedIn: true, role, username });
  };

  const handleRegister = (account: UserAccount): boolean => {
    if (users.find(u => u.username === account.username)) return false;
    setUsers([...users, account]);
    return true;
  };

  const handleLogout = () => {
    setAuth({ isLoggedIn: false, role: null, username: null });
    setView('home');
    setCart([]);
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const cartTotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const cartCount = cart.reduce((acc, item) => acc + item.quantity, 0);

  const confirmPayment = () => {
    if (cart.length === 0) return;

    const newOrder: Order = {
      id: Math.random().toString(36).substring(7).toUpperCase(),
      items: [...cart],
      totalAmount: cartTotal,
      date: new Date().toLocaleString('id-ID'),
      status: 'Selesai',
      paymentMethod
    };

    setOrders(prev => [newOrder, ...prev]);
    setCart([]);
    setView('home');
    alert(`Pembayaran via ${paymentMethod} Berhasil!\nNomor Pesanan: #${newOrder.id}`);
  };

  const deleteProduct = (id: string) => {
    setProducts(prev => prev.filter(p => p.id !== id));
  };

  const addProduct = (p: Product) => {
    setProducts(prev => [p, ...prev]);
  };

  if (!auth.isLoggedIn) {
    return <Login onLogin={handleLogin} onRegister={handleRegister} registeredUsers={users} />;
  }

  if (view === 'admin' && auth.role === 'admin') {
    return (
      <AdminDashboard 
        orders={orders} 
        onBack={() => setView('home')} 
        products={products}
        onAddProduct={addProduct}
        onDeleteProduct={deleteProduct}
      />
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-[#f8fafc]">
      {/* Navbar */}
      <nav className="bg-white/90 backdrop-blur-md border-b sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('home')}>
            <div className="w-10 h-10 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-blue-200">
              <ShoppingBag className="w-6 h-6" />
            </div>
            <span className="text-xl font-black text-gray-900 tracking-tight">MWSTORE</span>
          </div>

          <div className="hidden md:flex flex-1 max-w-md mx-8">
            <div className="relative w-full group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 group-focus-within:text-blue-600 transition-colors" />
              <input 
                type="text"
                placeholder="Cari produk impian..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full bg-gray-100 border-none rounded-xl py-2 pl-10 pr-4 text-sm focus:ring-2 focus:ring-blue-500 transition-all outline-none"
              />
            </div>
          </div>

          <div className="flex items-center gap-2 sm:gap-4">
            {auth.role === 'admin' && (
              <button 
                onClick={() => setView('admin')}
                className={`p-2 transition-colors flex items-center gap-1 ${view === 'admin' ? 'text-blue-600' : 'text-gray-500 hover:text-blue-600'}`}
              >
                <Settings className="w-5 h-5" />
                <span className="hidden lg:inline text-sm font-bold">Panel Admin</span>
              </button>
            )}

            <button 
              onClick={() => setView('cart')}
              className={`relative p-2 transition-colors ${view === 'cart' ? 'text-blue-600' : 'text-gray-700 hover:text-blue-600'}`}
            >
              <ShoppingCart className="w-6 h-6" />
              {cartCount > 0 && (
                <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] font-bold w-5 h-5 flex items-center justify-center rounded-full border-2 border-white">
                  {cartCount}
                </span>
              )}
            </button>

            <div className="flex items-center gap-3 pl-2 border-l border-gray-100">
              <div className="text-right hidden sm:block">
                <p className="text-xs font-bold text-gray-900">{auth.username}</p>
                <p className="text-[10px] text-gray-400 uppercase font-black tracking-tighter">{auth.role}</p>
              </div>
              <button onClick={handleLogout} className="p-2 text-gray-400 hover:text-red-500 transition-colors" title="Keluar">
                <LogOut className="w-5 h-5" />
              </button>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl mx-auto px-4 py-8 w-full">
        {view === 'home' && (
          <>
            <div className="relative rounded-[2.5rem] overflow-hidden bg-blue-600 p-8 md:p-16 mb-12 text-white shadow-2xl shadow-blue-200">
              <div className="max-w-xl relative z-10">
                <div className="inline-block px-3 py-1 bg-blue-500/30 rounded-full text-xs font-black uppercase tracking-widest mb-4">
                  Trend Belanja 2024
                </div>
                <h1 className="text-4xl md:text-5xl font-black mb-6 leading-tight">
                  Halo, {auth.username}!<br/>
                  Katalog Terlengkap Menanti.
                </h1>
                <p className="text-blue-100 text-lg mb-8 leading-relaxed opacity-90">
                  MWSTORE menghadirkan koleksi produk pilihan dari gadget hingga kamera terbaru untuk mendukung gaya hidup digital Anda.
                </p>
                <button className="bg-white text-blue-600 px-8 py-4 rounded-2xl font-black hover:bg-blue-50 transition-all flex items-center gap-2 shadow-xl shadow-blue-900/20 active:scale-95">
                  Mulai Belanja Sekarang <ChevronRight className="w-5 h-5" />
                </button>
              </div>
              <div className="absolute -bottom-10 -right-10 w-64 h-64 bg-white/10 rounded-full blur-3xl" />
              <div className="absolute top-0 right-0 w-1/3 h-full hidden lg:block opacity-10">
                <LayoutGrid className="w-full h-full p-12" />
              </div>
            </div>

            <div className="flex flex-wrap gap-2 mb-10 items-center overflow-x-auto pb-2 scrollbar-hide">
              <span className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mr-4 shrink-0">Filter Kategori:</span>
              {categories.map(cat => (
                <button
                  key={cat}
                  onClick={() => setSelectedCategory(cat)}
                  className={`px-6 py-3 rounded-2xl text-sm font-bold transition-all shrink-0 ${
                    selectedCategory === cat 
                      ? 'bg-blue-600 text-white shadow-xl shadow-blue-100' 
                      : 'bg-white text-gray-500 hover:bg-gray-50 border border-gray-100'
                  }`}
                >
                  {cat}
                </button>
              ))}
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
              {filteredProducts.map(product => (
                <ProductCard key={product.id} product={product} onAddToCart={addToCart} />
              ))}
            </div>

            {filteredProducts.length === 0 && (
              <div className="text-center py-20 bg-white rounded-[2rem] border-2 border-dashed border-gray-100">
                <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-6">
                  <AlertCircle className="w-8 h-8 text-gray-300" />
                </div>
                <h3 className="text-xl font-black text-gray-900 mb-2">Belum Ada Produk</h3>
                <p className="text-gray-400 font-medium">Katalog sedang dalam pembaruan atau filter tidak cocok.</p>
              </div>
            )}
          </>
        )}

        {view === 'cart' && (
          <div className="max-w-5xl mx-auto">
            <h2 className="text-4xl font-black mb-10 tracking-tight">Keranjang Belanja</h2>
            {cart.length === 0 ? (
              <div className="bg-white rounded-[2.5rem] p-20 text-center border border-gray-100 shadow-sm">
                <div className="w-28 h-28 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-8">
                  <ShoppingCart className="w-12 h-12 text-gray-200" />
                </div>
                <h3 className="text-2xl font-black mb-3">Keranjang Masih Kosong</h3>
                <p className="text-gray-400 mb-10 font-medium">Ayo jelajahi katalog MWSTORE dan pilih produk impianmu!</p>
                <button 
                  onClick={() => setView('home')}
                  className="bg-blue-600 text-white px-10 py-4 rounded-2xl font-black hover:bg-blue-700 transition-all shadow-xl shadow-blue-50"
                >
                  Lihat Katalog Produk
                </button>
              </div>
            ) : (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
                <div className="lg:col-span-2 space-y-6">
                  {cart.map(item => (
                    <div key={item.id} className="bg-white p-6 rounded-3xl shadow-sm border border-gray-50 flex gap-6 group hover:shadow-xl transition-all duration-500">
                      <div className="w-28 h-28 rounded-2xl overflow-hidden shrink-0 border border-gray-50">
                        <img src={item.image} alt={item.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />
                      </div>
                      <div className="flex-1 flex flex-col justify-between">
                        <div>
                          <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest">{item.category}</span>
                          <h3 className="font-bold text-lg text-gray-900">{item.name}</h3>
                          <p className="text-blue-600 font-black text-xl mt-1">{formatIDR(item.price)}</p>
                        </div>
                        <div className="flex items-center justify-between mt-4">
                          <div className="flex items-center gap-6 bg-gray-50 rounded-2xl px-4 py-2 border border-gray-100">
                            <button onClick={() => updateQuantity(item.id, -1)} className="p-1 hover:text-blue-600 transition-colors">
                              <Minus className="w-4 h-4" />
                            </button>
                            <span className="font-black text-gray-900">{item.quantity}</span>
                            <button onClick={() => updateQuantity(item.id, 1)} className="p-1 hover:text-blue-600 transition-colors">
                              <Plus className="w-4 h-4" />
                            </button>
                          </div>
                          <button onClick={() => removeFromCart(item.id)} className="text-red-400 hover:text-red-600 hover:bg-red-50 p-3 rounded-xl transition-all">
                            <Trash2 className="w-5 h-5" />
                          </button>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>

                <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-gray-100 h-fit sticky top-24">
                  <h3 className="text-xl font-black mb-8">Ringkasan Pesanan</h3>
                  <div className="space-y-4 mb-10">
                    <div className="flex justify-between text-gray-500 font-medium">
                      <span>Total Barang</span>
                      <span className="text-gray-900 font-bold">{cartCount} Pcs</span>
                    </div>
                    <div className="flex justify-between text-gray-500 font-medium">
                      <span>Subtotal</span>
                      <span className="text-gray-900 font-bold">{formatIDR(cartTotal)}</span>
                    </div>
                    <div className="h-px bg-gray-100 my-4" />
                    <div className="flex justify-between items-center">
                      <span className="text-lg font-bold text-gray-900">Total Akhir</span>
                      <span className="text-2xl font-black text-blue-600">{formatIDR(cartTotal)}</span>
                    </div>
                  </div>
                  <button 
                    onClick={() => setView('checkout')}
                    className="w-full bg-blue-600 text-white py-5 rounded-2xl font-black text-lg flex items-center justify-center gap-3 hover:bg-blue-700 shadow-2xl shadow-blue-100 transition-all active:scale-95"
                  >
                    Checkout Sekarang
                    <ChevronRight className="w-6 h-6" />
                  </button>
                </div>
              </div>
            )}
          </div>
        )}

        {view === 'checkout' && (
          <div className="max-w-5xl mx-auto">
            <button onClick={() => setView('cart')} className="flex items-center gap-2 text-gray-400 hover:text-blue-600 mb-8 font-black text-xs uppercase tracking-widest transition-colors">
              <ChevronRight className="w-4 h-4 rotate-180" />
              Kembali Ke Keranjang
            </button>
            <h2 className="text-4xl font-black mb-10 tracking-tight">Langkah Terakhir</h2>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
              <div className="space-y-8">
                <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-gray-100">
                  <h3 className="font-black text-xl mb-8 flex items-center gap-3">
                    <div className="w-8 h-8 bg-blue-100 rounded-lg flex items-center justify-center">
                      <Wallet className="w-5 h-5 text-blue-600" />
                    </div>
                    Pilih Cara Bayar
                  </h3>
                  <div className="space-y-4">
                    {[
                      { id: 'QRIS', icon: QrCode, desc: 'Instan via OVO, Dana, GoPay' },
                      { id: 'Transfer Bank', icon: Building2, desc: 'BCA, Mandiri, BNI' },
                      { id: 'E-Wallet', icon: Wallet, desc: 'Konfirmasi via Aplikasi' },
                    ].map(method => (
                      <button
                        key={method.id}
                        onClick={() => setPaymentMethod(method.id)}
                        className={`w-full flex items-center gap-4 p-5 rounded-[1.5rem] border-2 transition-all text-left ${
                          paymentMethod === method.id 
                            ? 'border-blue-600 bg-blue-50/50' 
                            : 'border-gray-50 hover:border-gray-200'
                        }`}
                      >
                        <div className={`p-4 rounded-2xl ${paymentMethod === method.id ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-500'}`}>
                          <method.icon className="w-6 h-6" />
                        </div>
                        <div className="flex-1">
                          <p className="font-black text-gray-900">{method.id}</p>
                          <p className="text-xs text-gray-400 font-bold">{method.desc}</p>
                        </div>
                        {paymentMethod === method.id && <div className="w-6 h-6 bg-blue-600 rounded-full flex items-center justify-center shadow-lg"><CheckCircle2 className="w-4 h-4 text-white" /></div>}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              <div className="bg-white p-10 rounded-[2.5rem] shadow-sm border border-gray-100 h-fit">
                <h3 className="font-black text-xl mb-8">Detail Pembayaran</h3>
                <div className="space-y-6 mb-10">
                  <div className="max-h-52 overflow-y-auto space-y-4 pr-2 custom-scrollbar">
                    {cart.map(item => (
                      <div key={item.id} className="flex justify-between text-sm">
                        <span className="text-gray-500 font-bold">{item.name} <span className="text-gray-300 ml-1">x{item.quantity}</span></span>
                        <span className="font-black text-gray-900">{formatIDR(item.price * item.quantity)}</span>
                      </div>
                    ))}
                  </div>
                  <div className="h-px bg-gray-100" />
                  <div className="flex justify-between items-center py-2">
                    <span className="text-gray-400 text-xs font-black uppercase">Metode</span>
                    <span className="text-blue-600 font-black text-sm px-3 py-1 bg-blue-50 rounded-lg">{paymentMethod}</span>
                  </div>
                  <div className="flex justify-between items-center text-3xl font-black pt-4 text-gray-900">
                    <span>Total</span>
                    <span className="text-blue-600">{formatIDR(cartTotal)}</span>
                  </div>
                </div>
                <button 
                  onClick={confirmPayment}
                  className="w-full bg-blue-600 text-white py-5 rounded-2xl font-black text-lg flex items-center justify-center gap-3 hover:bg-blue-700 shadow-2xl shadow-blue-100 transition-all active:scale-95"
                >
                  <CreditCard className="w-6 h-6" />
                  Konfirmasi Bayar
                </button>
                <p className="text-[10px] text-gray-400 text-center mt-6 font-bold uppercase tracking-widest">
                  Transaksi Aman Terenkripsi oleh MWSTORE
                </p>
              </div>
            </div>
          </div>
        )}
