const CACHE_NAME = 'mwstore-v1';
self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      return cache.addAll(['./', './index.html', './manifest.json']);
    })
  );
});

self.addEventListener('fetch', (event) => {
  event.respondWith(
    caches.match(event.request).then((response) => {
      return response || fetch(event.request);
    })
  );
});

import React, { useState, useMemo } from 'react';
import { ShoppingBag, Search, ChevronRight, LayoutGrid, Trash2, Plus, Minus, CreditCard, AlertCircle, ShoppingCart, Settings, LogOut, Wallet, QrCode, Building2, CheckCircle2, Copy, MessageCircle, Mail, RefreshCw, Download, Info } from 'lucide-react';
import { Product, CartItem, Order, View, AuthState, UserRole, UserAccount } from './types';
import { MOCK_PRODUCTS, formatIDR } from './constants';
import ProductCard from './components/ProductCard';
import AiAssistant from './components/AiAssistant';
import AdminDashboard from './components/AdminDashboard';
import Login from './components/Login';

const APP_VERSION = "v2.5.0-Gold";

const App: React.FC = () => {
  const [products, setProducts] = useState<Product[]>(MOCK_PRODUCTS);
  const [users, setUsers] = useState<UserAccount[]>([]);
  const [auth, setAuth] = useState<AuthState>({
    isLoggedIn: false,
    role: null,
    username: null
  });
  const [view, setView] = useState<View>('home');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('Semua');
  const [paymentMethod, setPaymentMethod] = useState('DANA');
  const [isUpdating, setIsUpdating] = useState(false);
  const [showInstallGuide, setShowInstallGuide] = useState(false);

  const categories = ['Semua', ...new Set(products.map(p => p.category))];

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = selectedCategory === 'Semua' || p.category === selectedCategory;
      return matchesSearch && matchesCategory;
    });
  }, [searchQuery, selectedCategory, products]);

  const handleLogin = (role: UserRole, username: string) => {
    setAuth({ isLoggedIn: true, role, username });
  };

  const handleRegister = (account: UserAccount): boolean => {
    if (users.find(u => u.username === account.username)) return false;
    setUsers([...users, account]);
    return true;
  };

  const handleLogout = () => {
    setAuth({ isLoggedIn: false, role: null, username: null });
    setView('home');
    setCart([]);
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const cartTotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const cartCount = cart.reduce((acc, item) => acc + item.quantity, 0);

  const confirmPayment = () => {
    if (cart.length === 0) return;

    const newOrder: Order = {
      id: Math.random().toString(36).substring(7).toUpperCase(),
      items: [...cart],
      totalAmount: cartTotal,
      date: new Date().toLocaleString('id-ID'),
      status: 'Selesai',
      paymentMethod
    };

    setOrders(prev => [newOrder, ...prev]);
    setCart([]);
    setView('home');
    alert(`Pesanan Terkirim!\nSilakan transfer ke Admin via ${paymentMethod} (083845890648) sebesar ${formatIDR(cartTotal)}.\nNomor Pesanan: #${newOrder.id}\nHubungi Admin jika sudah bayar.`);
  };

  const handleUpdateApp = () => {
    setIsUpdating(true);
    setTimeout(() => {
      setIsUpdating(false);
      alert("Aplikasi MWSTORE sudah menggunakan versi terbaru (" + APP_VERSION + ")");
    }, 1500);
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    alert('Nomor disalin!');
  };

  if (!auth.isLoggedIn) {
    return <Login onLogin={handleLogin} onRegister={handleRegister} registeredUsers={users} />;
  }

  if (view === 'admin' && auth.role === 'admin') {
    return (
      <AdminDashboard 
        orders={orders} 
        onBack={() => setView('home')} 
        products={products}
        users={users}
        onAddProduct={(p) => setProducts(prev => [p, ...prev])}
        onDeleteProduct={(id) => setProducts(prev => prev.filter(p => p.id !== id))}
      />
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-[#f8fafc]">
      {/* Banner Panduan Instal */}
