        <div className="flex items-center gap-2">
           <Info className="w-3 h-3" />
           Cara Download: Klik Titik Tiga (Chrome) > 'Tambahkan ke Layar Utama'
        </div>
        <button onClick={() => setShowInstallGuide(true)} className="underline ml-4">Pelajari Selengkapnya</button>
      </div>

      <nav className="bg-white/90 backdrop-blur-md border-b sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('home')}>
            <div className="w-10 h-10 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-blue-200">
              <ShoppingBag className="w-6 h-6" />
            </div>
            <span className="text-xl font-black text-gray-900 tracking-tight">MWSTORE</span>
          </div>

          <div className="hidden md:flex flex-1 max-w-md mx-8">
            <div className="relative w-full group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 group-focus-within:text-blue-600 transition-colors" />
              <input 
                type="text"
                placeholder="Cari gadget idaman..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full bg-gray-100 border-none rounded-xl py-2 pl-10 pr-4 text-sm focus:ring-2 focus:ring-blue-500 transition-all outline-none"
              />
            </div>
          </div>

          <div className="flex items-center gap-2 sm:gap-4">
            <button 
              onClick={() => setShowInstallGuide(true)}
              className="p-2 text-blue-600 hover:bg-blue-50 rounded-xl transition-all flex items-center gap-1"
              title="Download Aplikasi"
            >
              <Download className="w-5 h-5" />
              <span className="hidden lg:inline text-[10px] font-black uppercase">Download App</span>
            </button>

            {auth.role === 'admin' && (
              <button 
                onClick={() => setView('admin')}
                className={`p-2 transition-colors flex items-center gap-1 ${view === 'admin' ? 'text-blue-600' : 'text-gray-500 hover:text-blue-600'}`}
              >
                <Settings className="w-5 h-5" />
                <span className="hidden lg:inline text-sm font-bold uppercase tracking-tighter">Admin</span>
              </button>
            )}

            <button 
              onClick={() => setView('cart')}
              className={`relative p-2 transition-colors ${view === 'cart' ? 'text-blue-600' : 'text-gray-700 hover:text-blue-600'}`}
            >
              <ShoppingCart className="w-6 h-6" />
              {cartCount > 0 && (
