import React, { useState, useMemo } from 'react';
import { ShoppingBag, Search, ChevronRight, LayoutGrid, Trash2, Plus, Minus, CreditCard, AlertCircle, ShoppingCart, Settings, LogOut, Wallet, QrCode, Building2, CheckCircle2, Copy, MessageCircle, Mail, RefreshCw, Download, Info, Share2, ExternalLink, X } from 'lucide-react';
import { Product, CartItem, Order, View, AuthState, UserRole, UserAccount } from './types';
import { MOCK_PRODUCTS, formatIDR } from './constants';
import ProductCard from './components/ProductCard';
import AiAssistant from './components/AiAssistant';
import AdminDashboard from './components/AdminDashboard';
import Login from './components/Login';

const APP_VERSION = "v2.5.0-Gold";

const App: React.FC = () => {
  const [products, setProducts] = useState<Product[]>(MOCK_PRODUCTS);
  const [users, setUsers] = useState<UserAccount[]>([]);
  const [auth, setAuth] = useState<AuthState>({
    isLoggedIn: false,
    role: null,
    username: null
  });
  const [view, setView] = useState<View>('home');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('Semua');
  const [paymentMethod, setPaymentMethod] = useState('DANA');
  const [isUpdating, setIsUpdating] = useState(false);
  const [showInstallGuide, setShowInstallGuide] = useState(false);
  const [showShareModal, setShowShareModal] = useState(false);

  const categories = ['Semua', ...new Set(products.map(p => p.category))];

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = selectedCategory === 'Semua' || p.category === selectedCategory;
      return matchesSearch && matchesCategory;
    });
  }, [searchQuery, selectedCategory, products]);

  const handleLogin = (role: UserRole, username: string) => {
    setAuth({ isLoggedIn: true, role, username });
  };

  const handleRegister = (account: UserAccount): boolean => {
    if (users.find(u => u.username === account.username)) return false;
    setUsers([...users, account]);
    return true;
  };

  const handleLogout = () => {
    setAuth({ isLoggedIn: false, role: null, username: null });
    setView('home');
    setCart([]);
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const cartTotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const cartCount = cart.reduce((acc, item) => acc + item.quantity, 0);

  const confirmPayment = () => {
    if (cart.length === 0) return;

    const newOrder: Order = {
      id: Math.random().toString(36).substring(7).toUpperCase(),
      items: [...cart],
      totalAmount: cartTotal,
      date: new Date().toLocaleString('id-ID'),
      status: 'Selesai',
      paymentMethod
    };

    setOrders(prev => [newOrder, ...prev]);
    setCart([]);
    setView('home');
    alert(`Pesanan Terkirim!\nSilakan transfer ke Admin via ${paymentMethod} (083845890648) sebesar ${formatIDR(cartTotal)}.\nNomor Pesanan: #${newOrder.id}\nHubungi Admin jika sudah bayar.`);
  };

  const handleUpdateApp = () => {
    setIsUpdating(true);
    setTimeout(() => {
      setIsUpdating(false);
      alert("Aplikasi MWSTORE sudah menggunakan versi terbaru (" + APP_VERSION + ")");
    }, 1500);
  };

  const copyToClipboard = (text: string, message: string = 'Nomor disalin!') => {
    navigator.clipboard.writeText(text);
    alert(message);
  };

  const currentAppUrl = window.location.href;

  if (!auth.isLoggedIn) {
    return <Login onLogin={handleLogin} onRegister={handleRegister} registeredUsers={users} />;
  }

  if (view === 'admin' && auth.role === 'admin') {
    return (
      <AdminDashboard 
        orders={orders} 
        onBack={() => setView('home')} 
        products={products}
        users={users}
        onAddProduct={(p) => setProducts(prev => [p, ...prev])}
        onDeleteProduct={(id) => setProducts(prev => prev.filter(p => p.id !== id))}
      />
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-[#f8fafc]">
      {/* Banner Panduan Instal */}
      <div className="bg-blue-700 text-white text-[10px] py-2 px-4 flex justify-between items-center font-black uppercase tracking-widest overflow-hidden whitespace-nowrap">
        <div className="flex items-center gap-2">
           <Info className="w-3 h-3" />
           Cara Download: Klik Titik Tiga (Chrome) > 'Tambahkan ke Layar Utama'
        </div>
        <button onClick={() => setShowInstallGuide(true)} className="underline ml-4">Pelajari Selengkapnya</button>
      </div>

      <nav className="bg-white/90 backdrop-blur-md border-b sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('home')}>
            <div className="w-10 h-10 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-blue-200">
              <ShoppingBag className="w-6 h-6" />
            </div>
            <span className="text-xl font-black text-gray-900 tracking-tight">MWSTORE</span>
          </div>

          <div className="hidden md:flex flex-1 max-w-md mx-8">
            <div className="relative w-full group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 group-focus-within:text-blue-600 transition-colors" />
              <input 
                type="text"
                placeholder="Cari gadget idaman..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full bg-gray-100 border-none rounded-xl py-2 pl-10 pr-4 text-sm focus:ring-2 focus:ring-blue-500 transition-all outline-none"
              />
            </div>
          </div>

          <div className="flex items-center gap-2 sm:gap-4">
            <button 
              onClick={() => setShowShareModal(true)}
              className="p-2 text-blue-600 hover:bg-blue-50 rounded-xl transition-all flex items-center gap-1"
              title="Dapatkan Link Aplikasi"
            >
              <Share2 className="w-5 h-5" />
              <span className="hidden lg:inline text-[10px] font-black uppercase">Share App</span>
            </button>

            {auth.role === 'admin' && (
              <button 
                onClick={() => setView('admin')}
                className={`p-2 transition-colors flex items-center gap-1 ${view === 'admin' ? 'text-blue-600' : 'text-gray-500 hover:text-blue-600'}`}
              >
                <Settings className="w-5 h-5" />
                <span className="hidden lg:inline text-sm font-bold uppercase tracking-tighter">Admin</span>
              </button>
            )}

            <button 
              onClick={() => setView('cart')}
              className={`relative p-2 transition-colors ${view === 'cart' ? 'text-blue-600' : 'text-gray-700 hover:text-blue-600'}`}
            >
              <ShoppingCart className="w-6 h-6" />
              {cartCount > 0 && (
                <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] font-bold w-5 h-5 flex items-center justify-center rounded-full border-2 border-white">
                  {cartCount}
                </span>
              )}
            </button>

            <div className="flex items-center gap-3 pl-2 border-l border-gray-100">
              <button onClick={handleLogout} className="p-2 text-gray-400 hover:text-red-500 transition-colors" title="Keluar">
                <LogOut className="w-5 h-5" />
              </button>
            </div>
          </div>
        </div>
      </nav>

      {/* Modal Bagikan Link / QR Code */}
      {showShareModal && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[110] flex items-center justify-center p-4">
           <div className="bg-white rounded-[2.5rem] w-full max-w-md p-8 relative animate-in zoom-in-95 duration-300">
              <button onClick={() => setShowShareModal(false)} className="absolute top-6 right-6 p-2 bg-gray-100 rounded-full text-gray-400 hover:text-gray-900 transition-all">
                 <X className="w-5 h-5" />
              </button>

              <div className="text-center mb-8">
                 <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center text-white mx-auto mb-4 shadow-xl shadow-blue-100">
