import React, { useState, useMemo, useEffect } from 'react';
import { ShoppingBag, Search, ChevronRight, LayoutGrid, Trash2, Plus, Minus, CreditCard, AlertCircle, ShoppingCart, Settings, LogOut, Wallet, QrCode, Building2, CheckCircle2, Copy, MessageCircle, Mail, RefreshCw, Download, Info, Share2, ExternalLink, X, Smartphone, Globe, Gamepad2 } from 'lucide-react';
import { Product, CartItem, Order, View, AuthState, UserRole, UserAccount } from './types';
import { MOCK_PRODUCTS, formatIDR } from './constants';
import ProductCard from './components/ProductCard';
import AiAssistant from './components/AiAssistant';
import AdminDashboard from './components/AdminDashboard';
import Login from './components/Login';

const APP_VERSION = "v2.6.0-Gaming";

const App: React.FC = () => {
  const [products, setProducts] = useState<Product[]>(MOCK_PRODUCTS);
  const [users, setUsers] = useState<UserAccount[]>([]);
  const [auth, setAuth] = useState<AuthState>({
    isLoggedIn: false,
    role: null,
    username: null
  });
  const [view, setView] = useState<View>('home');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('Semua');
  const [paymentMethod, setPaymentMethod] = useState('DANA');
  const [isUpdating, setIsUpdating] = useState(false);
  const [showInstallGuide, setShowInstallGuide] = useState(false);
  const [showShareModal, setShowShareModal] = useState(false);

  const categories = ['Semua', ...new Set(products.map(p => p.category))];

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = selectedCategory === 'Semua' || p.category === selectedCategory;
      return matchesSearch && matchesCategory;
    });
  }, [searchQuery, selectedCategory, products]);

  const handleLogin = (role: UserRole, username: string) => {
    setAuth({ isLoggedIn: true, role, username });
  };

  const handleRegister = (account: UserAccount): boolean => {
    if (users.find(u => u.username === account.username)) return false;
    setUsers([...users, account]);
    return true;
  };

  const handleLogout = () => {
    setAuth({ isLoggedIn: false, role: null, username: null });
    setView('home');
    setCart([]);
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
