/**
 * Service ini mensimulasikan logika dari class Api PHP Anda.
 * Dalam aplikasi nyata, ini akan melakukan fetch() ke backend PHP.
 */
export const ApiService = {
  // Simpan orders di localStorage untuk simulasi database
  saveOrder: (order: Order) => {
    const existing = JSON.parse(localStorage.getItem('mw_orders') || '[]');
    localStorage.setItem('mw_orders', JSON.stringify([order, ...existing]));
  },

  getOrders: (): Order[] => {
    return JSON.parse(localStorage.getItem('mw_orders') || '[]');
  },

  // Simulasi cek status pesanan (API: status)
  checkStatus: (orderId: string): string => {
    const orders = ApiService.getOrders();
    const order = orders.find(o => o.id === orderId);
    return order ? order.status : 'not found';
  },

  // Simulasi membuat pesanan baru (API: order)
  createOrder: (username: string, items: CartItem[], total: number, method: string): Order => {
    const newOrder: Order = {
      id: Math.floor(100000 + Math.random() * 900000).toString(),
      items: [...items],
      totalAmount: total,
      date: new Date().toLocaleString('id-ID'),
      status: 'Pending',
      paymentMethod: method,
      username: username
    };
    ApiService.saveOrder(newOrder);
    return newOrder;
  }
};

