  const [cart, setCart] = useState<CartItem[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('Semua');
  const [paymentMethod, setPaymentMethod] = useState<'Saldo Akun' | 'QRIS / E-Wallet'>('Saldo Akun');
  const [showInstallGuide, setShowInstallGuide] = useState(false);
  const [showShareModal, setShowShareModal] = useState(false);
  const [copied, setCopied] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);

  // Sync users from service
  useEffect(() => {
    setUsers(ApiService.getUsers());
  }, [view]);

  // Update Auth State Balance when users change
  useEffect(() => {
    if (auth.username) {
      const bal = ApiService.getBalance(auth.username);
      setAuth(prev => ({ ...prev, balance: bal }));
    }
  }, [users, auth.username]);

  const categories = ['Semua', ...new Set(products.map(p => p.category))];

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = selectedCategory === 'Semua' || p.category === selectedCategory;
      return matchesSearch && matchesCategory;
    });
  }, [searchQuery, selectedCategory, products]);

  const handleLogin = (role: UserRole, username: string) => {
    const bal = ApiService.getBalance(username);
    setAuth({ isLoggedIn: true, role, username, balance: bal });
  };

  const handleRegister = (account: UserAccount): boolean => {
    const existing = ApiService.getUsers();
    if (existing.find(u => u.username === account.username)) return false;

    // Memberikan saldo awal Rp 50.000 untuk pendaftaran baru
    const newUsers = [...existing, { ...account, balance: 50000 }];
    localStorage.setItem('mw_users', JSON.stringify(newUsers));
    setUsers(newUsers);
    return true;
  };

  const handleLogout = () => {
    setAuth({ isLoggedIn: false, role: null, username: null, balance: null });
    setView('home');
    setCart([]);
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const cartTotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const cartCount = cart.reduce((acc, item) => acc + item.quantity, 0);

  const handleProcessPayment = () => {
    if (cart.length === 0) return;

    // Cek saldo jika metode pembayaran adalah Saldo Akun
    if (paymentMethod === 'Saldo Akun' && (auth.balance || 0) < cartTotal) {
      alert("Saldo Anda tidak cukup! Silakan top up atau pilih metode pembayaran lain.");
      return;
    }

    setIsProcessing(true);
    setTimeout(() => {
      ApiService.createOrder(
        auth.username || 'Guest', 
        cart, 
        cartTotal, 
        paymentMethod
      );
      setCart([]);
      setIsProcessing(false);
      setView('orders');
      // Refresh local user data to show new balance
      setUsers(ApiService.getUsers());
    }, 1500);
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  if (!auth.isLoggedIn) {
    return <Login onLogin={handleLogin} onRegister={handleRegister} registeredUsers={users} />;
  }

  if (view === 'admin' && auth.role === 'admin') {
    return (
      <AdminDashboard 
        orders={ApiService.getOrders()} 
        onBack={() => setView('home')} 
        products={products}
        users={users}
        onAddProduct={(p) => setProducts(prev => [p, ...prev])}
        onDeleteProduct={(id) => setProducts(prev => prev.filter(p => p.id !== id))}
      />
    );
  }

  return (
