                <div className="flex flex-wrap gap-4">
                  <button onClick={() => {setSelectedCategory('Top Up Game'); window.scrollTo({top: 500, behavior: 'smooth'})}} className="bg-white text-blue-700 px-8 py-4 rounded-2xl font-black hover:bg-blue-50 transition-all flex items-center gap-2 shadow-xl shadow-blue-900/20">
