                  <div className="flex items-center gap-3 bg-indigo-600/30 backdrop-blur-md border border-white/20 px-6 py-4 rounded-2xl">
                     <Wallet className="w-5 h-5 text-indigo-300" />
                     <span className="font-black text-sm">{formatIDR(auth.balance || 0)}</span>
