                       <div className="flex items-center gap-4 p-4 bg-indigo-50 rounded-2xl border border-indigo-100">
                          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white">
                             <Wallet className="w-5 h-5" />
                          </div>
                          <div>
                             <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Saldo Tersedia</p>
                             <p className="font-black text-indigo-700">{formatIDR(auth.balance || 0)}</p>
                          </div>
                       </div>

                       <div className="mt-10 h-px bg-gray-100 mb-6" />

                       <div className="space-y-4">
                          <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Ringkasan Tagihan</p>
                          {cart.map(item => (
                            <div key={item.id} className="flex justify-between text-xs font-bold text-gray-600">
                               <span>{item.name} x{item.quantity}</span>
                               <span>{formatIDR(item.price * item.quantity)}</span>
                            </div>
                          ))}
                          <div className="pt-4 border-t border-gray-50 flex justify-between items-end">
                             <span className="text-[10px] font-black text-gray-900 uppercase">Total Bayar</span>
                             <span className="text-xl font-black text-blue-600">{formatIDR(cartTotal)}</span>
                          </div>
                       </div>
                    </div>

                    {(paymentMethod === 'Saldo Akun' && (auth.balance || 0) < cartTotal) && (
                       <div className="p-6 bg-red-50 rounded-3xl border border-red-100 flex items-start gap-4">
                          <AlertCircle className="w-5 h-5 text-red-600 shrink-0" />
                          <p className="text-[11px] text-red-700 font-bold leading-relaxed uppercase tracking-tighter">
                             Saldo Anda tidak mencukupi untuk pesanan ini. Silakan hubungi admin untuk Top Up Saldo.
                          </p>
                       </div>
                    )}
                 </div>

                 {/* Main Payment Options */}
                 <div className="lg:col-span-2 space-y-4">
                    {/* Saldo Akun Option */}
                    <button 
                       onClick={() => setPaymentMethod('Saldo Akun')}
                       className={`w-full p-8 rounded-[2.5rem] border-2 transition-all text-left flex items-center justify-between ${
                          paymentMethod === 'Saldo Akun' ? 'bg-indigo-50 border-indigo-600' : 'bg-white border-gray-100 hover:border-gray-200'
                       }`}
                    >
                       <div className="flex items-center gap-6">
                          <div className={`w-14 h-14 rounded-2xl flex items-center justify-center ${paymentMethod === 'Saldo Akun' ? 'bg-indigo-600 text-white shadow-xl' : 'bg-gray-50 text-gray-400'}`}>
                             <Coins className="w-7 h-7" />
                          </div>
                          <div>
                             <h4 className="font-black text-gray-900 text-lg">Saldo Akun MW-Wallet</h4>
                             <p className="text-sm text-gray-500 font-medium">Bayar instan & otomatis tanpa scan QR.</p>
                          </div>
                       </div>
                       <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center ${paymentMethod === 'Saldo Akun' ? 'border-indigo-600' : 'border-gray-200'}`}>
                          {paymentMethod === 'Saldo Akun' && <div className="w-3 h-3 bg-indigo-600 rounded-full" />}
                       </div>
                    </button>

                    {/* QRIS Option */}
                    <button 
                       onClick={() => setPaymentMethod('QRIS / E-Wallet')}
                       className={`w-full p-8 rounded-[2.5rem] border-2 transition-all text-left flex items-center justify-between ${
                          paymentMethod === 'QRIS / E-Wallet' ? 'bg-blue-50 border-blue-600' : 'bg-white border-gray-100 hover:border-gray-200'
                       }`}
                    >
                       <div className="flex items-center gap-6">
                          <div className={`w-14 h-14 rounded-2xl flex items-center justify-center ${paymentMethod === 'QRIS / E-Wallet' ? 'bg-blue-600 text-white shadow-xl' : 'bg-gray-50 text-gray-400'}`}>
                             <QrCode className="w-7 h-7" />
                          </div>
                          <div>
                             <h4 className="font-black text-gray-900 text-lg">QRIS / E-Wallet</h4>
                             <p className="text-sm text-gray-500 font-medium">Scan QR DANA, GOPAY, ShopeePay, OVO.</p>
                          </div>
                       </div>
                       <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center ${paymentMethod === 'QRIS / E-Wallet' ? 'border-blue-600' : 'border-gray-200'}`}>
                          {paymentMethod === 'QRIS / E-Wallet' && <div className="w-3 h-3 bg-blue-600 rounded-full" />}
                       </div>
                    </button>

                    {paymentMethod === 'QRIS / E-Wallet' ? (
                       <div className="bg-white p-10 rounded-[3rem] border border-gray-100 shadow-sm text-center animate-in slide-in-from-top-4">
                          <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-6">Pindai QR Untuk Membayar</p>
                          <div className="relative w-full max-w-[250px] mx-auto p-4 bg-white border-4 border-gray-50 rounded-[2.5rem] shadow-xl">
                             <img src={`https://api.qrserver.com/v1/create-qr-code/?size=300x300&data=083845890648`} className="w-full h-auto rounded-xl" alt="QRIS" />
                          </div>
                          <p className="mt-8 text-xs font-bold text-gray-500">Scan QR di atas lalu klik konfirmasi di bawah.</p>
                       </div>
                    ) : (
                       <div className="bg-indigo-600 text-white p-10 rounded-[3rem] shadow-xl animate-in slide-in-from-top-4">
                          <div className="flex justify-between items-center mb-10">
                             <h4 className="font-black text-xl">Konfirmasi Saldo</h4>
                             <Coins className="w-10 h-10 opacity-20" />
                          </div>
                          <div className="grid grid-cols-2 gap-6">
                             <div className="bg-white/10 p-4 rounded-2xl">
                                <p className="text-[9px] font-black uppercase opacity-60 mb-1">Saldo Saat Ini</p>
                                <p className="font-black">{formatIDR(auth.balance || 0)}</p>
                             </div>
                             <div className="bg-white/10 p-4 rounded-2xl">
                                <p className="text-[9px] font-black uppercase opacity-60 mb-1">Potongan Tagihan</p>
                                <p className="font-black text-red-300">-{formatIDR(cartTotal)}</p>
                             </div>
                          </div>
                          <div className="mt-8 p-4 bg-white/10 rounded-2xl border border-white/10">
                             <p className="text-[9px] font-black uppercase opacity-60 mb-1">Sisa Saldo Setelah Bayar</p>
                             <p className="text-2xl font-black">{formatIDR(Math.max(0, (auth.balance || 0) - cartTotal))}</p>
                          </div>
                       </div>
                    )}

                    <button 
                       onClick={handleProcessPayment}
                       disabled={isProcessing || (paymentMethod === 'Saldo Akun' && (auth.balance || 0) < cartTotal)}
                       className="w-full py-6 bg-green-600 text-white rounded-[2rem] font-black uppercase tracking-widest text-xs flex items-center justify-center gap-3 shadow-xl hover:bg-green-700 transition-all active:scale-95 disabled:opacity-50"
                    >
                       {isProcessing ? <RefreshCw className="w-6 h-6 animate-spin" /> : <CheckCircle2 className="w-6 h-6" />}
                       {paymentMethod === 'Saldo Akun' ? 'Bayar Pakai Saldo Sekarang' : 'Konfirmasi Sudah Transfer'}
                    </button>
                 </div>
              </div>
           </div>
        )}

        {view === 'orders' && (
           <div className="max-w-4xl mx-auto py-10 animate-in fade-in duration-300">
              <h2 className="text-3xl font-black mb-10 text-gray-900 flex items-center gap-4">
                 <Receipt className="w-8 h-8 text-blue-600" />
                 Laporan Pesanan
              </h2>

              {ApiService.getOrders().filter(o => o.username === auth.username || auth.role === 'admin').length === 0 ? (
                 <div className="text-center py-20 bg-white rounded-[3rem] border border-gray-100 shadow-sm">
                    <p className="text-gray-400 font-bold">Belum ada riwayat belanja.</p>
                 </div>
              ) : (
                 <div className="space-y-6">
                    {ApiService.getOrders().filter(o => o.username === auth.username || auth.role === 'admin').map(order => (
                       <div key={order.id} className="bg-white p-8 rounded-[2.5rem] border border-gray-100 shadow-sm flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                          <div>
                             <div className="flex items-center gap-3 mb-2">
                                <span className="px-3 py-1 bg-blue-50 text-blue-600 rounded-lg text-[10px] font-black uppercase tracking-widest border border-blue-100">#{order.id}</span>
                                <span className="text-[10px] font-black text-gray-400 uppercase">{order.date}</span>
                             </div>
                             <h4 className="font-black text-gray-900 mb-2 truncate max-w-[250px]">
                                {order.items.map(i => i.name).join(', ')}
                             </h4>
                             <div className="flex items-center gap-2">
                                <span className="text-blue-600 font-black text-xl">{formatIDR(order.totalAmount)}</span>
                                <span className="text-[9px] font-black px-2 py-0.5 bg-gray-100 text-gray-500 rounded uppercase tracking-tighter">{order.paymentMethod}</span>
                             </div>
                          </div>

                          <div className="flex flex-col items-end gap-3 w-full md:w-auto">
                             <div className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center gap-2 ${
                                order.status === 'Selesai' ? 'bg-green-100 text-green-600' : 
                                order.status === 'Pending' ? 'bg-orange-100 text-orange-600' : 'bg-blue-100 text-blue-600'
                             }`}>
                                {order.status === 'Pending' ? <Clock className="w-4 h-4" /> : <CheckCircle2 className="w-4 h-4" />}
                                {order.status}
                             </div>
                             <button className="text-[10px] font-black text-blue-600 uppercase tracking-widest hover:underline">Download Invois</button>
                          </div>
                       </div>
                    ))}
                 </div>
              )}
           </div>
        )}
      </main>

      <AiAssistant />

      <footer className="bg-white border-t py-20 mt-20">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <div className="flex items-center justify-center gap-2 mb-8">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white font-black shadow-lg shadow-blue-100">MW</div>
            <span className="text-2xl font-black text-gray-900 tracking-tighter">MWSTORE</span>
          </div>
          <p className="text-gray-400 text-[10px] font-black uppercase tracking-[0.4em] mb-12">Official MW-Wallet Enabled Commerce</p>
          <div className="flex flex-wrap justify-center gap-4">
             <button onClick={() => setShowShareModal(true)} className="flex items-center gap-2 px-8 py-4 bg-gray-50 rounded-2xl text-[10px] font-black uppercase tracking-widest text-gray-600 border border-gray-100 hover:bg-white transition-all">
                <Download className="w-4 h-4" />
                Dapatkan App
             </button>
             <a href="https://wa.me/6283845890648" target="_blank" className="flex items-center gap-2 px-8 py-4 bg-green-50 rounded-2xl text-[10px] font-black uppercase tracking-widest text-green-600 border border-green-100 hover:bg-white transition-all">
                <MessageCircle className="w-4 h-4" />
                Customer Service
             </a>
          </div>
          <div className="mt-20 pt-10 border-t border-gray-50 text-[9px] font-black text-gray-300 uppercase tracking-widest">
             <p>© 2024 MWSTORE OFFICIAL - WALLET & SALDO ECOSYSTEM</p>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

export interface Product {
  id: string;
  name: string;
  description: string;
  price: number;
  category: string;
  image: string;
  rating: number;
  stock: number;
}

export interface CartItem extends Product {
  quantity: number;
}

export interface Order {
  id: string;
  items: CartItem[];
  totalAmount: number;
  date: string;
  status: 'Pending' | 'Proses' | 'Selesai' | 'Dibatalkan';
  paymentMethod: string;
  username: string;
}

export type View = 'home' | 'cart' | 'admin' | 'checkout' | 'orders' | 'topup';

export type UserRole = 'admin' | 'user' | null;

export interface UserAccount {
  username: string;
  password?: string;
  role: 'user' | 'admin';
  balance: number;
}

export interface AuthState {
  isLoggedIn: boolean;
  role: UserRole;
  username: string | null;
  balance: number | null;
}

import React, { useState, useMemo, useEffect } from 'react';
import { ShoppingBag, Search, ChevronRight, LayoutGrid, Trash2, Plus, Minus, CreditCard, AlertCircle, ShoppingCart, Settings, LogOut, Wallet, QrCode, Building2, CheckCircle2, Copy, MessageCircle, Mail, RefreshCw, Download, Info, Share2, ExternalLink, X, Smartphone, Globe, Gamepad2, Receipt, ShieldCheck, Banknote, Sparkles, Check, Scan, Save, MonitorSmartphone, Clock, Coins, ArrowUpCircle } from 'lucide-react';
import { Product, CartItem, Order, View, AuthState, UserRole, UserAccount } from './types';
import { MOCK_PRODUCTS, formatIDR } from './constants';
import ProductCard from './components/ProductCard';
import AiAssistant from './components/AiAssistant';
import AdminDashboard from './components/AdminDashboard';
import Login from './components/Login';
import { ApiService } from './services/apiService';

const APP_VERSION = "v3.3.0-TopUpReady";

const App: React.FC = () => {
  const [products, setProducts] = useState<Product[]>(MOCK_PRODUCTS);
  const [users, setUsers] = useState<UserAccount[]>(ApiService.getUsers());
  const [auth, setAuth] = useState<AuthState>({
    isLoggedIn: false,
    role: null,
    username: null,
    balance: null
  });
  const [view, setView] = useState<View>('home');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('Semua');
  const [paymentMethod, setPaymentMethod] = useState<'Saldo Akun' | 'QRIS / E-Wallet'>('Saldo Akun');
  const [isProcessing, setIsProcessing] = useState(false);
  const [topupAmount, setTopupAmount] = useState<number>(50000);

  // Sync users from service
  useEffect(() => {
    setUsers(ApiService.getUsers());
  }, [view]);

  // Update Auth State Balance when users change
  useEffect(() => {
    if (auth.username) {
      const bal = ApiService.getBalance(auth.username);
      setAuth(prev => ({ ...prev, balance: bal }));
    }
  }, [users, auth.username]);

  const categories = ['Semua', ...new Set(products.map(p => p.category))];

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = selectedCategory === 'Semua' || p.category === selectedCategory;
      return matchesSearch && matchesCategory;
    });
  }, [searchQuery, selectedCategory, products]);

  const handleLogin = (role: UserRole, username: string) => {
    const bal = ApiService.getBalance(username);
    setAuth({ isLoggedIn: true, role, username, balance: bal });
  };

  const handleRegister = (account: UserAccount): boolean => {
    const existing = ApiService.getUsers();
    if (existing.find(u => u.username === account.username)) return false;

    const newUsers = [...existing, { ...account, balance: 50000 }];
    localStorage.setItem('mw_users', JSON.stringify(newUsers));
    setUsers(newUsers);
    return true;
  };

  const handleLogout = () => {
    setAuth({ isLoggedIn: false, role: null, username: null, balance: null });
    setView('home');
    setCart([]);
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const removeFromCart = (productId: string) => {
    setCart(prev => prev.filter(item => item.id !== productId));
  };

  const cartTotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const cartCount = cart.reduce((acc, item) => acc + item.quantity, 0);

  const handleProcessPayment = () => {
    if (cart.length === 0) return;

    if (paymentMethod === 'Saldo Akun' && (auth.balance || 0) < cartTotal) {
      alert("Saldo Anda tidak cukup! Silakan top up.");
      setView('topup');
      return;
    }

    setIsProcessing(true);
    setTimeout(() => {
      ApiService.createOrder(
        auth.username || 'Guest', 
        cart, 
        cartTotal, 
        paymentMethod
      );
      setCart([]);
      setIsProcessing(false);
      setView('orders');
      setUsers(ApiService.getUsers());
    }, 1500);
  };

  const handleProcessTopup = () => {
    if (topupAmount < 1000) return;
    setIsProcessing(true);

    // Simulasi verifikasi pembayaran QRIS
    setTimeout(() => {
      if (auth.username) {
        const current = ApiService.getBalance(auth.username);
        ApiService.updateBalance(auth.username, current + topupAmount);
        setUsers(ApiService.getUsers());
        setIsProcessing(false);
        alert(`Top Up Berhasil! Saldo sebesar ${formatIDR(topupAmount)} telah ditambahkan.`);
        setView('home');
      }
    }, 2000);
  };

  if (!auth.isLoggedIn) {
    return <Login onLogin={handleLogin} onRegister={handleRegister} registeredUsers={users} />;
  }

  if (view === 'admin' && auth.role === 'admin') {
    return (
      <AdminDashboard 
        orders={ApiService.getOrders()} 
        onBack={() => setView('home')} 
        products={products}
        users={users}
        onAddProduct={(p) => setProducts(prev => [p, ...prev])}
        onDeleteProduct={(id) => setProducts(prev => prev.filter(p => p.id !== id))}
      />
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-[#f8fafc]">
      <div className="bg-indigo-600 text-white text-[10px] py-2 px-4 flex justify-center items-center font-black uppercase tracking-widest gap-2">
         <Wallet className="w-3 h-3" />
         Gunakan Saldo MW-Wallet untuk Transaksi Lebih Cepat & Aman
      </div>

      <nav className="bg-white/95 backdrop-blur-md border-b sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('home')}>
            <div className="w-9 h-9 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg">
              <ShoppingBag className="w-5 h-5" />
            </div>
            <span className="text-lg font-black text-gray-900 tracking-tighter">MWSTORE</span>
          </div>

          <div className="flex items-center gap-3">
            {/* Balance Badge - Clickable to Top Up */}
            <button 
              onClick={() => setView('topup')}
              className="flex items-center gap-2 px-3 py-1.5 md:px-4 md:py-2 bg-indigo-50 border border-indigo-100 rounded-2xl hover:bg-indigo-100 transition-colors"
            >
               <div className="w-6 h-6 bg-indigo-600 rounded-lg flex items-center justify-center text-white shadow-sm">
                  <Plus className="w-3.5 h-3.5" />
               </div>
               <div className="flex flex-col items-start text-left">
                  <span className="text-[8px] font-black text-indigo-400 uppercase tracking-widest leading-none">Isi Saldo</span>
                  <span className="text-xs font-black text-indigo-700 leading-tight">{formatIDR(auth.balance || 0)}</span>
               </div>
            </button>

            <button onClick={() => setView('orders')} className="p-2 text-gray-500 hover:text-blue-600 transition-colors">
              <Receipt className="w-6 h-6" />
            </button>
            <button onClick={() => setView('cart')} className="relative p-2 text-gray-700 hover:text-blue-600 transition-colors">
              <ShoppingCart className="w-6 h-6" />
              {cartCount > 0 && (
                <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[9px] font-bold w-4 h-4 flex items-center justify-center rounded-full border-2 border-white">
                  {cartCount}
                </span>
              )}
            </button>
            <button onClick={handleLogout} className="p-2 text-gray-400 hover:text-red-500 transition-colors"><LogOut className="w-5 h-5" /></button>
          </div>
        </div>
      </nav>

      <main className="flex-1 max-w-7xl mx-auto px-4 py-8 w-full">
        {view === 'home' && (
          <>
            <div className="relative rounded-[2.5rem] overflow-hidden bg-gradient-to-br from-indigo-700 to-blue-900 p-8 md:p-14 mb-12 text-white shadow-2xl">
              <div className="max-w-xl relative z-10">
                <div className="inline-flex items-center gap-2 px-3 py-1 bg-white/10 rounded-full text-[10px] font-black uppercase tracking-widest mb-4 border border-white/10">
                  <ShieldCheck className="w-3 h-3 text-green-400" />
                  MW-WALLET READY {APP_VERSION}
                </div>
                <h1 className="text-4xl md:text-5xl font-black mb-6 leading-[1.1]">
                  Dompet Digital<br/>Favorit Gamers.
                </h1>
                <p className="text-blue-100/80 text-base md:text-lg mb-8 leading-relaxed font-medium">
                  Top up diamond, UC, atau genesis makin praktis dengan saldo MW-Wallet. Isi saldo sekarang dan nikmati kecepatan transaksi!
                </p>
                <div className="flex flex-wrap gap-4">
                  <button onClick={() => setView('topup')} className="bg-white text-blue-700 px-8 py-4 rounded-2xl font-black hover:bg-blue-50 transition-all flex items-center gap-2 shadow-xl shadow-blue-900/20">
                    <ArrowUpCircle className="w-5 h-5" />
                    Isi Saldo Sekarang
                  </button>
                  <div className="flex items-center gap-3 bg-white/10 backdrop-blur-md border border-white/20 px-6 py-4 rounded-2xl">
                     <Coins className="w-5 h-5 text-indigo-300" />
                     <span className="font-black text-sm">{formatIDR(auth.balance || 0)}</span>
                  </div>
                </div>
              </div>
            </div>

            <div className="flex flex-wrap gap-2 mb-10 items-center overflow-x-auto pb-4 no-scrollbar">
              {categories.map(cat => (
                <button
                  key={cat}
                  onClick={() => setSelectedCategory(cat)}
                  className={`px-6 py-3 rounded-2xl text-xs font-black uppercase tracking-wider transition-all shrink-0 ${
                    selectedCategory === cat 
                      ? 'bg-blue-600 text-white shadow-xl scale-105' 
                      : 'bg-white text-gray-500 hover:bg-gray-50 border border-gray-100'
                  }`}
                >
                  {cat}
                </button>
              ))}
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8 mb-20">
              {filteredProducts.map(product => (
                <ProductCard key={product.id} product={product} onAddToCart={addToCart} />
              ))}
            </div>
          </>
        )}

        {view === 'topup' && (
           <div className="max-w-4xl mx-auto py-10 animate-in slide-in-from-bottom-5 duration-500">
              <div className="text-center mb-12">
                 <h2 className="text-4xl font-black text-gray-900 mb-4 flex items-center justify-center gap-4">
                    <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white">
                       <Plus className="w-7 h-7" />
                    </div>
                    Top Up Saldo
                 </h2>
                 <p className="text-gray-500 font-medium">Pilih nominal dan metode pembayaran untuk menambah saldo Anda.</p>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
                 {/* Pilih Nominal */}
                 <div className="space-y-8">
                    <div className="bg-white p-8 rounded-[3rem] border border-gray-100 shadow-sm">
                       <h3 className="font-black text-gray-900 mb-6 uppercase tracking-widest text-[10px]">Pilih Nominal Top Up</h3>
                       <div className="grid grid-cols-2 gap-3">
                          {[10000, 20000, 50000, 100000, 200000, 500000].map(amount => (
                             <button 
                                key={amount}
                                onClick={() => setTopupAmount(amount)}
                                className={`py-4 rounded-2xl font-black text-sm transition-all border-2 ${
                                   topupAmount === amount 
                                   ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg shadow-indigo-100' 
                                   : 'bg-white text-gray-600 border-gray-50 hover:border-indigo-100 hover:bg-indigo-50/30'
                                }`}
                             >
                                {formatIDR(amount)}
                             </button>
                          ))}
                       </div>

                       <div className="mt-8 pt-8 border-t border-gray-50">
                          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1 mb-2 block">Atau Nominal Custom</label>
                          <div className="relative">
                             <span className="absolute left-5 top-1/2 -translate-y-1/2 font-black text-gray-400 text-lg">Rp</span>
                             <input 
                               type="number" 
                               value={topupAmount}
                               onChange={(e) => setTopupAmount(Number(e.target.value))}
                               className="w-full bg-gray-50 border-none rounded-2xl py-5 pl-14 pr-6 focus:ring-4 focus:ring-indigo-500/10 outline-none font-black text-lg text-gray-900"
                               placeholder="Min. 1.000"
                             />
                          </div>
                       </div>
                    </div>

                    <div className="bg-indigo-50 p-6 rounded-[2.5rem] border border-indigo-100 flex items-start gap-4">
                       <Info className="w-5 h-5 text-indigo-600 shrink-0 mt-1" />
                       <p className="text-[11px] text-indigo-700 font-bold leading-relaxed uppercase tracking-tighter">
                          Proses verifikasi saldo berlangsung instan setelah pembayaran terdeteksi oleh sistem kami. Hubungi admin jika mengalami kendala.
                       </p>
                    </div>
                 </div>

                 {/* Scan & Bayar */}
                 <div className="bg-white p-10 rounded-[4rem] border border-gray-100 shadow-xl flex flex-col items-center text-center">
                    <div className="inline-flex items-center gap-2 px-4 py-2 bg-blue-50 text-blue-600 rounded-full text-[10px] font-black uppercase tracking-widest mb-8 border border-blue-100">
                       <Scan className="w-3 h-3" />
                       Metode QRIS Instan
                    </div>

                    <div className="relative p-6 bg-white border-4 border-gray-50 rounded-[3rem] shadow-2xl mb-8 group overflow-hidden">
                       <img 
                          src={`https://api.qrserver.com/v1/create-qr-code/?size=300x300&data=topup_mwstore_${auth.username}_${topupAmount}&bgcolor=ffffff&color=4338ca`} 
                          className="w-56 h-56 rounded-xl relative z-10" 
                          alt="QR Topup" 
                       />
                       <div className="absolute inset-0 bg-indigo-600/5 group-hover:bg-transparent transition-colors duration-500"></div>
                    </div>

                    <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Total Transfer</p>
                    <p className="text-4xl font-black text-indigo-600 mb-10">{formatIDR(topupAmount)}</p>

                    <button 
                       onClick={handleProcessTopup}
                       disabled={isProcessing || topupAmount < 1000}
                       className="w-full py-6 bg-indigo-600 text-white rounded-[2rem] font-black uppercase tracking-widest text-xs flex items-center justify-center gap-3 shadow-xl hover:bg-indigo-700 transition-all active:scale-95 disabled:opacity-50"
                    >
                       {isProcessing ? (
                          <>
                             <RefreshCw className="w-6 h-6 animate-spin" />
                             Memproses Saldo...
                          </>
                       ) : (
                          <>
                             <CheckCircle2 className="w-6 h-6" />
                             Konfirmasi Pembayaran
                          </>
                       )}
                    </button>

                    <p className="mt-6 text-[10px] font-bold text-gray-400 uppercase tracking-tighter">
                       Klik tombol di atas setelah Anda berhasil melakukan transfer melalui QRIS.
                    </p>
                 </div>
              </div>
           </div>
        )}

        {/* Existing Views: cart, checkout, orders remain unchanged or updated for topup redirect */}
        {view === 'cart' && (
           <div className="max-w-4xl mx-auto py-10 animate-in fade-in duration-300">
              <h2 className="text-3xl font-black mb-10 text-gray-900">Keranjang Belanja</h2>
              {cart.length === 0 ? (
                <div className="text-center py-20 bg-white rounded-[3rem] border border-gray-100 shadow-sm">
                   <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-6">
                      <ShoppingCart className="w-8 h-8 text-gray-200" />
                   </div>
                   <p className="text-gray-400 font-bold">Keranjang kosong.</p>
                   <button onClick={() => setView('home')} className="mt-6 bg-blue-600 text-white px-8 py-3 rounded-xl font-black uppercase tracking-widest text-[10px]">Cari Produk</button>
                </div>
              ) : (
                <div className="space-y-4">
                  {cart.map(item => (
                    <div key={item.id} className="bg-white p-6 rounded-[2rem] border border-gray-100 flex items-center gap-6 shadow-sm">
                       <img src={item.image} className="w-16 h-16 rounded-2xl object-cover" />
                       <div className="flex-1">
                          <p className="font-black text-gray-900">{item.name}</p>
                          <p className="text-blue-600 font-black text-lg">{formatIDR(item.price)}</p>
                       </div>
                       <button onClick={() => removeFromCart(item.id)} className="text-red-400 p-2 hover:bg-red-50 rounded-xl transition-all"><Trash2 className="w-5 h-5" /></button>
                    </div>
                  ))}
                  <div className="mt-10 p-10 bg-indigo-600 text-white rounded-[3rem] flex flex-col md:flex-row justify-between items-center shadow-2xl gap-6">
                    <div>
                      <p className="text-[10px] font-black uppercase opacity-60 tracking-widest mb-1">Total Tagihan</p>
                      <p className="text-4xl font-black">{formatIDR(cartTotal)}</p>
                    </div>
                    <button onClick={() => setView('checkout')} className="bg-white text-blue-600 px-10 py-5 rounded-2xl font-black uppercase tracking-widest text-xs shadow-lg">Pilih Pembayaran</button>
                  </div>
                </div>
              )}
           </div>
        )}

        {view === 'checkout' && (
           <div className="max-w-5xl mx-auto py-10 animate-in slide-in-from-bottom-5 duration-500">
              <h2 className="text-3xl font-black mb-10">Pilih Metode Pembayaran</h2>

              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                 <div className="lg:col-span-1 space-y-6">
                    <div className="bg-white p-8 rounded-[2.5rem] border border-gray-100 shadow-sm">
                       <h3 className="font-black text-gray-900 mb-6 uppercase tracking-widest text-xs">Informasi Akun</h3>
                       <div className="flex items-center gap-4 p-4 bg-indigo-50 rounded-2xl border border-indigo-100">
                          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white">
                             <Wallet className="w-5 h-5" />
                          </div>
                          <div>
                             <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Saldo Tersedia</p>
                             <p className="font-black text-indigo-700">{formatIDR(auth.balance || 0)}</p>
                          </div>
                       </div>

                       <div className="mt-10 h-px bg-gray-100 mb-6" />

                       <div className="space-y-4">
                          <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Ringkasan Tagihan</p>
                          {cart.map(item => (
                            <div key={item.id} className="flex justify-between text-xs font-bold text-gray-600">
                               <span>{item.name} x{item.quantity}</span>
                               <span>{formatIDR(item.price * item.quantity)}</span>
                            </div>
                          ))}
                          <div className="pt-4 border-t border-gray-50 flex justify-between items-end">
                             <span className="text-[10px] font-black text-gray-900 uppercase">Total Bayar</span>
                             <span className="text-xl font-black text-blue-600">{formatIDR(cartTotal)}</span>
                          </div>
                       </div>
                    </div>

                    {(paymentMethod === 'Saldo Akun' && (auth.balance || 0) < cartTotal) && (
                       <div className="p-6 bg-red-50 rounded-3xl border border-red-100 flex flex-col gap-4">
                          <div className="flex items-start gap-4">
                             <AlertCircle className="w-5 h-5 text-red-600 shrink-0" />
                             <p className="text-[11px] text-red-700 font-bold leading-relaxed uppercase tracking-tighter">
                                Saldo Anda tidak mencukupi untuk pesanan ini.
                             </p>
                          </div>
                          <button onClick={() => setView('topup')} className="w-full bg-red-600 text-white py-3 rounded-xl text-[10px] font-black uppercase tracking-widest">Top Up Sekarang</button>
                       </div>
                    )}
                 </div>

                 <div className="lg:col-span-2 space-y-4">
                    <button onClick={() => setPaymentMethod('Saldo Akun')} className={`w-full p-8 rounded-[2.5rem] border-2 transition-all text-left flex items-center justify-between ${paymentMethod === 'Saldo Akun' ? 'bg-indigo-50 border-indigo-600' : 'bg-white border-gray-100 hover:border-gray-200'}`}>
                       <div className="flex items-center gap-6">
                          <div className={`w-14 h-14 rounded-2xl flex items-center justify-center ${paymentMethod === 'Saldo Akun' ? 'bg-indigo-600 text-white shadow-xl' : 'bg-gray-50 text-gray-400'}`}>
                             <Coins className="w-7 h-7" />
                          </div>
                          <div>
                             <h4 className="font-black text-gray-900 text-lg">Saldo Akun MW-Wallet</h4>
                             <p className="text-sm text-gray-500 font-medium">Bayar instan & otomatis tanpa scan QR.</p>
                          </div>
                       </div>
                       <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center ${paymentMethod === 'Saldo Akun' ? 'border-indigo-600' : 'border-gray-200'}`}>
                          {paymentMethod === 'Saldo Akun' && <div className="w-3 h-3 bg-indigo-600 rounded-full" />}
                       </div>
                    </button>

                    <button onClick={() => setPaymentMethod('QRIS / E-Wallet')} className={`w-full p-8 rounded-[2.5rem] border-2 transition-all text-left flex items-center justify-between ${paymentMethod === 'QRIS / E-Wallet' ? 'bg-blue-50 border-blue-600' : 'bg-white border-gray-100 hover:border-gray-200'}`}>
                       <div className="flex items-center gap-6">
                          <div className={`w-14 h-14 rounded-2xl flex items-center justify-center ${paymentMethod === 'QRIS / E-Wallet' ? 'bg-blue-600 text-white shadow-xl' : 'bg-gray-50 text-gray-400'}`}>
                             <QrCode className="w-7 h-7" />
                          </div>
                          <div>
                             <h4 className="font-black text-gray-900 text-lg">QRIS / E-Wallet</h4>
                             <p className="text-sm text-gray-500 font-medium">Scan QR DANA, GOPAY, ShopeePay, OVO.</p>
                          </div>
                       </div>
                       <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center ${paymentMethod === 'QRIS / E-Wallet' ? 'border-blue-600' : 'border-gray-200'}`}>
                          {paymentMethod === 'QRIS / E-Wallet' && <div className="w-3 h-3 bg-blue-600 rounded-full" />}
                       </div>
                    </button>

                    <button 
                       onClick={handleProcessPayment}
                       disabled={isProcessing || (paymentMethod === 'Saldo Akun' && (auth.balance || 0) < cartTotal)}
                       className="w-full py-6 bg-green-600 text-white rounded-[2rem] font-black uppercase tracking-widest text-xs flex items-center justify-center gap-3 shadow-xl hover:bg-green-700 transition-all active:scale-95 disabled:opacity-50"
                    >
                       {isProcessing ? <RefreshCw className="w-6 h-6 animate-spin" /> : <CheckCircle2 className="w-6 h-6" />}
                       {paymentMethod === 'Saldo Akun' ? 'Bayar Pakai Saldo Sekarang' : 'Konfirmasi Sudah Transfer'}
                    </button>
                 </div>
              </div>
           </div>
        )}

        {view === 'orders' && (
           <div className="max-w-4xl mx-auto py-10 animate-in fade-in duration-500">
              <h2 className="text-3xl font-black mb-10 text-gray-900 flex items-center gap-4">
                 <Receipt className="w-8 h-8 text-blue-600" />
                 Laporan Pesanan
              </h2>

              {ApiService.getOrders().filter(o => o.username === auth.username || auth.role === 'admin').length === 0 ? (
                 <div className="text-center py-20 bg-white rounded-[3rem] border border-gray-100 shadow-sm">
                    <p className="text-gray-400 font-bold">Belum ada riwayat belanja.</p>
                 </div>
              ) : (
                 <div className="space-y-6">
                    {ApiService.getOrders().filter(o => o.username === auth.username || auth.role === 'admin').map(order => (
                       <div key={order.id} className="bg-white p-8 rounded-[2.5rem] border border-gray-100 shadow-sm flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                          <div>
                             <div className="flex items-center gap-3 mb-2">
                                <span className="px-3 py-1 bg-blue-50 text-blue-600 rounded-lg text-[10px] font-black uppercase tracking-widest border border-blue-100">#{order.id}</span>
                                <span className="text-[10px] font-black text-gray-400 uppercase">{order.date}</span>
                             </div>
                             <h4 className="font-black text-gray-900 mb-2 truncate max-w-[250px]">
                                {order.items.map(i => i.name).join(', ')}
                             </h4>
                             <div className="flex items-center gap-2">
                                <span className="text-blue-600 font-black text-xl">{formatIDR(order.totalAmount)}</span>
                                <span className="text-[9px] font-black px-2 py-0.5 bg-gray-100 text-gray-500 rounded uppercase tracking-tighter">{order.paymentMethod}</span>
                             </div>
                          </div>

                          <div className="flex flex-col items-end gap-3 w-full md:w-auto">
                             <div className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center gap-2 ${
                                order.status === 'Selesai' ? 'bg-green-100 text-green-600' : 
                                order.status === 'Pending' ? 'bg-orange-100 text-orange-600' : 'bg-blue-100 text-blue-600'
                             }`}>
                                {order.status === 'Pending' ? <Clock className="w-4 h-4" /> : <CheckCircle2 className="w-4 h-4" />}
                                {order.status}
                             </div>
                             <button className="text-[10px] font-black text-blue-600 uppercase tracking-widest hover:underline">Download Invois</button>
                          </div>
                       </div>
                    ))}
                 </div>
              )}
           </div>
        )}
      </main>

      <AiAssistant />

      <footer className="bg-white border-t py-20 mt-20">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <div className="flex items-center justify-center gap-2 mb-8">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white font-black shadow-lg shadow-blue-100">MW</div>
            <span className="text-2xl font-black text-gray-900 tracking-tighter">MWSTORE</span>
          </div>
          <p className="text-gray-400 text-[10px] font-black uppercase tracking-[0.4em] mb-12">Official MW-Wallet Enabled Commerce</p>
          <div className="flex flex-wrap justify-center gap-4">
             <button className="flex items-center gap-2 px-8 py-4 bg-gray-50 rounded-2xl text-[10px] font-black uppercase tracking-widest text-gray-600 border border-gray-100 hover:bg-white transition-all">
                <Download className="w-4 h-4" />
                Dapatkan App
             </button>
             <a href="https://wa.me/6283845890648" target="_blank" className="flex items-center gap-2 px-8 py-4 bg-green-50 rounded-2xl text-[10px] font-black uppercase tracking-widest text-green-600 border border-green-100 hover:bg-white transition-all">
                <MessageCircle className="w-4 h-4" />
                Customer Service
             </a>
          </div>
          <div className="mt-20 pt-10 border-t border-gray-50 text-[9px] font-black text-gray-300 uppercase tracking-widest">
             <p>© 2024 MWSTORE OFFICIAL - WALLET & TOPUP ECOSYSTEM</p>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;
